-- ============================================================
-- Migration 040: Candidate Onboarding — Foundation (v0.6.0)
-- Run in Supabase SQL Editor (one block; idempotent)
-- Creates: onb_candidates, onb_questions (+86 seed), onb_attempts
-- ============================================================

-- ── Candidates ──────────────────────────────────────────────
CREATE TABLE IF NOT EXISTS onb_candidates (
  id                        UUID PRIMARY KEY DEFAULT gen_random_uuid(),
  created_at                TIMESTAMPTZ NOT NULL DEFAULT now(),
  updated_at                TIMESTAMPTZ NOT NULL DEFAULT now(),

  first_name                TEXT NOT NULL,
  last_name                 TEXT NOT NULL,
  email                     TEXT NOT NULL,

  -- 'invited' | 'testing' | 'test_passed' | 'applying'
  -- | 'application_submitted' | 'in_review' | 'axiscare_created'
  -- | 'converted' | 'withdrawn'
  status                    TEXT NOT NULL DEFAULT 'invited',

  access_token              TEXT,            -- sha256 hex of the raw magic-link token
  token_expires_at          TIMESTAMPTZ,

  invited_by                UUID REFERENCES profiles(id) ON DELETE SET NULL,
  invited_at                TIMESTAMPTZ NOT NULL DEFAULT now(),

  test_passed_at            TIMESTAMPTZ,
  application_submitted_at  TIMESTAMPTZ,
  axiscare_pushed_at        TIMESTAMPTZ,
  axiscare_applicant_id     INTEGER,
  converted_to_profile_id   UUID REFERENCES profiles(id) ON DELETE SET NULL
);

CREATE INDEX IF NOT EXISTS onb_candidates_status_idx ON onb_candidates (status, created_at DESC);
CREATE INDEX IF NOT EXISTS onb_candidates_token_idx  ON onb_candidates (access_token);
CREATE INDEX IF NOT EXISTS onb_candidates_email_idx  ON onb_candidates (lower(email));

-- ── Competency questions ────────────────────────────────────
CREATE TABLE IF NOT EXISTS onb_questions (
  id            UUID PRIMARY KEY DEFAULT gen_random_uuid(),
  created_at    TIMESTAMPTZ NOT NULL DEFAULT now(),
  domain        TEXT NOT NULL,
  prompt        TEXT NOT NULL,
  options       JSONB NOT NULL,          -- [{"key":"A","text":"..."}, ...]
  correct_key   TEXT NOT NULL,           -- 'A' | 'B' | 'C' | 'D'
  rationale     TEXT,
  active        BOOLEAN NOT NULL DEFAULT true,
  sort_order    INTEGER NOT NULL DEFAULT 0
);

CREATE INDEX IF NOT EXISTS onb_questions_active_idx ON onb_questions (active, sort_order);

-- ── Test attempts ───────────────────────────────────────────
CREATE TABLE IF NOT EXISTS onb_attempts (
  id               UUID PRIMARY KEY DEFAULT gen_random_uuid(),
  created_at       TIMESTAMPTZ NOT NULL DEFAULT now(),
  candidate_id     UUID NOT NULL REFERENCES onb_candidates(id) ON DELETE CASCADE,
  first_score      INTEGER,
  first_total      INTEGER,
  first_passed     BOOLEAN,
  answers          JSONB,                -- {question_id: {selected, correct, attempts}}
  mastery_reached  BOOLEAN NOT NULL DEFAULT false,
  started_at       TIMESTAMPTZ NOT NULL DEFAULT now(),
  completed_at     TIMESTAMPTZ
);

CREATE INDEX IF NOT EXISTS onb_attempts_candidate_idx ON onb_attempts (candidate_id, created_at DESC);

-- ── Seed: 86 competency questions ───────────────────────────
-- Re-runnable: clears the seeded bank, then re-inserts. Safe because
-- attempts store a snapshot of answers, not a FK to questions.
DELETE FROM onb_questions;

